var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"자, 이것은 오렌지 주스라고 부르는 것이다. 신맛이 나기 때문에 설탕을 많이 넣어야 하지.","JPN":"さて、これはオレンジジュースと呼ぶものだ。酸味があるので砂糖を多めに入れなければならぬ。","ENG":"Okay, this is called orange juice. Because it tastes sour, you have to put lots of sugar in it.","TWN":"你看，這個是柳橙汁，它的味道比較酸，所以要加很多糖！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_WATER_04"},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Okay.","TWN":"好！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그리고 이건 자몽 주스다. 쓴맛이 나기 때문에 설탕을 더~ 더 많이 넣어야 하지.","JPN":"そしてこれはグレープフルーツジュースだ。苦味があるから砂糖をもーっと多めに入れなければならぬ。","ENG":"And this is grapefruit juice. Because it tastes bitter, you have to put lots and lots of sugar in it.","TWN":"然後這是葡萄柚汁，它的味道偏苦澀，所以要加更多～的糖！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_WATER_05"},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에.","JPN":"わかりました。","ENG":"Okay...","TWN":"沒問題！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그리고 이건 포도랑 망고를 넣어서 만든 주스다! 어떠냐!","JPN":"そしてこれはブドウとマンゴーを入れて作ったジュースだ！　どうだ！","ENG":"And this is grape-mango juice! What do you think?","TWN":"最後再加入葡萄和芒果，就完成啦！怎麼樣！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저기… 주스 만드는 법은 이만하면 충분하지 않나요?","JPN":"あの……ジュースの作り方はこれくらいで十分ではないでしょうか？","ENG":"Hey... don't you think you've taught me enough juice recipes yet?","TWN":"請問…果汁的部分是不是先學到這裡就好？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여기 오시는 손님들은 보통 주스가 아니라 칵테일을 주문하실 텐데요.","JPN":"このお店に来るお客様たちはおそらくジュースではなく、\\nカクテルを注文されることが多いと思うのですが……","ENG":"Also, bar patrons usually order cocktails more often than juice.","TWN":"來這裡的客人應該不太會點果汁，大部分都是點雞尾酒居多吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"칵테일은 몰라. 맛없어.","JPN":"カクテルは知らない。まずいもん。","ENG":"I don't care about cocktails. I don't like them.","TWN":"雞尾酒我不會啦！又不好喝！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼 그레모리 씨께선 어째서 모모에게 제 교육을 맡기신 걸까요?","JPN":"では、グレモリーさんはなぜモモに私の教育を任せたのでしょうか？","ENG":"Okay, then how come Gremory wanted you to train me?","TWN":"那葛茉莉為什麼會請你負責訓練我呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"응? 그게 무슨 소리냐?","JPN":"うむ？　それはどういう意味だ？","ENG":"Huh? What do you mean?","TWN":"蛤？你在說什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨는 모모를 임금님이라고 부르던데요?","JPN":"グレモリーさんはモモを王様と呼んでいましたよ？","ENG":"Gremory calls you majesty.","TWN":"葛茉莉說你是國王？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"물론이다. 그레모리는 이 몸의 충직한 하수인이니라.","JPN":"もちろんだ。グレモリーは吾輩の忠実な下僕だからな。","ENG":"That's because she's my faithful subject.","TWN":"沒錯，葛茉莉是本王忠心的手下。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만, 그레모리 씨가 부하직원이라면 왜 굳이 모모가 여기서 일을 하고 계신 거죠?","JPN":"ですが、グレモリーさんが部下なら、なぜモモはここで働いているのですか？","ENG":"But if you're her employer, why are you working here instead of her?","TWN":"可是葛茉莉是手下的話，那為什麼是你在這裡做事呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그, 그건……","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"那是因為……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"원래 나처럼 대단한 마왕은 그만큼 일을 많이 해야 하는 법이니까…","JPN":"もともと吾輩のような偉大な魔王は、それだけたくさんの仕事をこなさないといけないから……","ENG":"That's because great Demon Lords like me must work hard...","TWN":"像我這麼偉大的魔王，本來就有很多事要做…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"……라고 그레모리가 그랬었는데……?","JPN":"……とグレモリーが言っていたけど……？","ENG":"Or so Gremory said...","TWN":"……葛茉莉是這麼說的吧……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하, 솔선수범이란 거군요.","JPN":"なるほど、率先垂範ということですね。","ENG":"Ah, you mean taking initiative.","TWN":"喔～～是以身作則的意思嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"솔슨…","JPN":"そ、そっ、せんしゅい……","ENG":"Taking initi…","TWN":"以什麼…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무, 무엄하구나! 이 몸 앞에서 그런 어려운 말을 쓰다니!","JPN":"お、愚か者め！　吾輩の前でそんな難しい言葉を使うとは！","ENG":"H-how dare you use such a difficult word in front of me?","TWN":"大…大膽！竟敢在本王面前我說聽不懂的話！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"죄송해요. 나쁜 뜻은 아니었어요.","JPN":"すみません、悪気はなかったんです。","ENG":"I'm sorry. I didn't mean anything bad.","TWN":"抱歉抱歉，我沒有惡意！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흥. 내게 공물을 바치면 용서를 생각해 보마.","JPN":"ふん。吾輩に供物を捧げたら許すことも考えてやろう。","ENG":"Hmpf! Bring me an offering, and maybe I'll forgive you.","TWN":"哼！你獻禮物給我的話，我就考慮原諒你！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"공물이요?","JPN":"供物ですか？","ENG":"Offering?","TWN":"獻禮物？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음… 지금은 딱히 가지고 있는 게 없는데요.","JPN":"うーん……今は手持ちがなくて……","ENG":"Mm... I don't have anything to give you right now.","TWN":"嗯…可是我現在身上什麼都沒有。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"발뺌해도 소용없다. 네 주머니에 튀어나온 그것을 똑똑히 보았노라.","JPN":"言い逃れようとしても無駄だ。\\nお前のポケットから出ているそれをはっきりと見たぞ。","ENG":"Lies! I saw what you pulled out of your pocket.","TWN":"想唬我是吧！我都看到啦！你口袋裡面那個是什麼！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"초코바요? 이걸로 괜찮은 건가요?","JPN":"チョコバーですか？　こんなものでいいんですか？","ENG":"You mean, this candy bar? Are you sure?","TWN":"你說巧克力棒？你只要這個嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"응. 바치거라.","JPN":"うむ。捧げるのだ。","ENG":"Yes. Gimme.","TWN":"嗯，拿給我！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"냠… 냠…","JPN":"もぐ……もぐ……","ENG":"*Nom, nom*","TWN":"啊姆啊姆…啊姆啊姆…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(우와… 꼬리를 흔들고 있어…)","JPN":"(うわあ……しっぽを振ってる……)","ENG":"(Wow, she's wagging her tail...)","TWN":"(哇…還有尾巴在搖欸…)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(역시, 악마가 아닌 이상 저런 게 가능할 리 없겠죠.)","JPN":"(やっぱり悪魔でもない限り、あんなことはできるわけがないでしょう。)","ENG":"(She definitely has to be a devil, right?)","TWN":"(長角又長尾巴的，說她不是魔鬼，鬼才相信咧！)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"더 없느냐?","JPN":"もうないのか？","ENG":"Don't you have more?","TWN":"還有嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아… 그렇게 말하셔도 지금은 돈이 없어서요.","JPN":"あ……そう言われましても、今は手持ちがなくて。","ENG":"Ah... Sorry, I don't have money to buy any more.","TWN":"呃…不好意思，那是我現在全身上下僅有的巧克力棒。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"월급이 들어오면 더 사드릴게요.","JPN":"お給料をもらったら、また買ってあげます。","ENG":"I'll get you more when I get my paycheck.","TWN":"等發薪水我再買給你。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"좋다. 그럼 너도 이제부터 이 몸의 하수인으로 삼아 주마.","JPN":"よかろう。じゃあ、お前もこれから吾輩の下僕にしてやる。","ENG":"Very well. As of today, I accept you as my subject.","TWN":"好吧，本王就收你當我的手下吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그리고 목이 마르구나. 이 몸의 전용 잔에 딸기우유를 담아오거라.","JPN":"それと喉が乾いてきたぞ。\\n吾輩の専用グラスにいちごミルクを入れてくるのだ。","ENG":"Now, I'm thirsty. Bring me some strawberry milk in my favorite cup.","TWN":"本王口渴，在本王專用的杯子裡倒滿草莓牛奶拿來給我！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아… 네!","JPN":"あ……はい！","ENG":"Ah... Okay!","TWN":"喔…好！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(귀여운 분홍색 머그컵… <color=#ffd34c>마왕 전용</color>이라고 쓰여 있네요.)","JPN":"(かわいいピンク色のマグカップ……<color=#ffd34c>魔王専用</color>と書いてありますね。)","ENG":"(A cute pink mug... \\"<color=#ffd34c>Demon Lord Only</color>\\" is written on it.)","TWN":"(可愛的粉紅色馬克杯…上面寫著<color=#ffd34c>魔王專用</color>。)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(어쩌면 지금이 정체를 확인할 좋은 기회예요.)","JPN":"(もしかしたら、今が正体を確認する良い機会かもしれません。)","ENG":"(Perhaps this is a good chance to identify her.)","TWN":"(或許現在是確認她是人是鬼的好機會！)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(우리 구마회가 자랑하는 특제 성수를 섞어 넣으면 악마인지 판별할 수 있겠죠.)","JPN":"(祓魔会が誇る特製聖水を混ぜれば、悪魔かどうか判別できるでしょう。)","ENG":"(I'm going to use some of the special holy water that the Exorcism Council is famous for to find out if she really is a devil.)","TWN":"(只要加入我們驅魔會最自豪的特製聖水，就可以知道她到底是不是魔鬼！)"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여기요. 드세요.","JPN":"どうぞ。召し上がってください。","ENG":"Here. Enjoy your milk.","TWN":"草莓牛奶送到，請享用。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"응? 뭔가 평소와 맛이 다른 것 같은데……?","JPN":"うむ？　いつものと味が違うような……？","ENG":"Mm? It tastes different than usual...","TWN":"嗯？味道怎麼跟平常不太一樣……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"커헉…!","JPN":"……ぐわっ！","ENG":"Khhhkkk!","TWN":"唔…！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이 악마다운 반응! 역시 제가 잘못 본 게 아니었어요!","JPN":"この悪魔らしい反応！　やっぱり私が見間違えたのではありませんでした！","ENG":"Such a typical response from devils! I knew I was right!","TWN":"這是魔鬼才會有的反應！我果然沒認錯！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그런데…","JPN":"ところで……","ENG":"By the way...","TWN":"不過…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"고작 성수 몇 방울의 효과가 이렇게 엄청났었나?","JPN":"聖水とはいえ数滴程度でこんなにすごい効果でしたっけ？","ENG":"Who knew just a few drops of the holy water could be so powerful?","TWN":"不過我才加幾滴聖水而已，怎麼反應這麼大？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"뭐, 어쨌든 신성에 거부반응을 보였으니까요.","JPN":"まあ、とにかく神聖に拒否反応を見せましたし。","ENG":"Well, she did react to its holiness.","TWN":"應該是邪惡遇到聖潔時會有的正常反應吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"곧 귀여운 모습 뒤에 감춰진 흉악한 본모습이 드러나겠죠.","JPN":"まもなくかわいい姿の裏に隠された凶悪な素顔が現れるでしょう。","ENG":"Soon, she'll reveal the ugly devilish form she's been hiding behind her cute appearance.","TWN":"快將你隱藏在這可愛外表底下的真面目顯露出來吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"조금만 기다리면… 곧 본모습이…","JPN":"もう少し待てば……本来の姿が……","ENG":"Soon, she will...","TWN":"還是再等一下…應該很快就…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Err?","TWN":"嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"알러지 반응입니다. 기도가 부어서 일시적으로 호흡기가 막혔나 보네요.","JPN":"アレルギー反応です。\\n一時的に気道が腫れて呼吸困難になったようですね。","ENG":"She had an allergic reaction to something. Her throat swelled up, temporarily blocking her airway.","TWN":"是過敏引起的反應，應該是氣管腫脹導致呼吸道阻塞。"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"다행히 지금은 상태가 많이 호전됐습니다.","JPN":"幸い、今は症状がだいぶ好転しています。","ENG":"Fortunately, the swelling has mostly gone away now.","TWN":"幸好目前狀況已經好轉。"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하아… 다행… 이네요.","JPN":"はぁ……よかった……です。","ENG":"Whew... I'm glad.","TWN":"呼…好險…。"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"으음, 이상하네. 지금까지 딸기우유를 마시고 문제가 생긴 적은 없었는데.","JPN":"うーん、変ね。今まではいちごミルクを飲んでも問題なかったのに。","ENG":"Hmm, this doesn't make sense. She's never had a problem drinking strawberry milk before.","TWN":"嗯嗯，真奇怪，她平時喝草莓牛奶也不會這樣？"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"익숙한 것도 조심하는 편이 좋습니다. 같은 유제품도 공장마다 취급이 조금씩 다르니까요.","JPN":"慣れているものでも気をつけたほうがいいでしょう。\\n同じ乳製品でも、工場によって製作工程が変わりますからね。","ENG":"You should be careful even with familiar products. Even the same milk is treated differently, depending on the factory.","TWN":"就算是常吃的東西也要注意，同樣是乳製品，但是乳源或是加工方式未必都一樣。"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 이제부터 딸기우유는 금지야.","JPN":"仕方ないわね。これからいちごミルクは禁止よ。","ENG":"Alright, no strawberry milk for you from now on.","TWN":"好吧，從現在開始禁止你喝草莓牛奶。"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"아, 안 돼!","JPN":"ヤ、ヤダ！","ENG":"N-no!","TWN":"不…不要！"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"돼.","JPN":"ヤダじゃないの。","ENG":"Yes.","TWN":"要。"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(성수의 성분에 알러지가 있을 줄이야. 미처 예상 못 했네요. 아무래도 다른 악마 검증 방법이 필요하겠어요.)","JPN":"(聖水の成分にアレルギーがあるとは予想外でした。\\nどうやら他の悪魔の検証方法を試す必要がありそうですね。)","ENG":"(Who knew she was allergic to holy water? I need something else to prove her devilish identity.)","TWN":"(沒想到聖水裡竟然有過敏原，真是始料未及。只好用其他方法來查證！)"},"stage":{"bg":"HOSPITAL","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"다음으로 교육할 것은 손님과의 대화다.","JPN":"次に教育してやるのはお客さんとの会話だ。","ENG":"Next, I'll teach you how to talk to your customers.","TWN":"接下來要教你怎麼和客人對話。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"상대의 심리를 분석하거나 공감하는 법에 대한 교육인가요?","JPN":"相手の心理を分析したり共感したりする方法についてですか？","ENG":"Do I have to know how to analyze and empathize with them psychologically?","TWN":"是要教我怎麼分析客人的心理，或是有同理心嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그… 그런 어려운 건 몰라.","JPN":"そ、そんな難しいことは知らん。","ENG":"I-I don't know anything about all that.","TWN":"呃…那個那麼難，我不會啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"아무튼, 지금부터는 손님들에게 하면 안 되는 것들을 하나씩 알려 주도록 하마!","JPN":"とにかく、これからお客さんにやってはいけないことを一つずつ教えてやろう！","ENG":"Anyway, I'll teach you what not to do to your customers, one at a time!","TWN":"總之，我現在告訴你的是，絕對不能對客人做的事！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"해선 안 되는 것?","JPN":"やってはいけないこと？","ENG":"What not to do?","TWN":"不能對客人做的事？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"첫째, 손님에게 초콜릿이나 사탕을 달라고 하지 않을 것!","JPN":"一つ目、お客さんにチョコレートやキャンディーをねだらないこと！","ENG":"First, don't ask your customers for chocolate or candy.","TWN":"第一，絕對不能跟客人要巧克力或是糖果！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"둘째, 손님을 하수인처럼 부려먹지 않을 것!","JPN":"二つ目、客を下僕のようにこき使わないこと！","ENG":"Second, don't treat your customers as if they're your subjects.","TWN":"第二，絕對不能把客人當手下使喚！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그리고 세 번째는… 뭐였지?","JPN":"そして三つ目は……何だっけ？","ENG":"And third... What was it?","TWN":"還有第三…是什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"혹시 손님 앞에서 음식을 먹지 말 것… 인가요?","JPN":"もしかして、お客様の前で食べ物を食べないこと……ですか？","ENG":"Could it be... \\"Don't eat food in front of your customers?\\"","TWN":"會不會是不能在客人面前飲食…對嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무엄하구나! 감히 이 몸의 말을 가로채다니!","JPN":"無礼者め！　吾輩の言葉を遮るなんて！","ENG":"How dare you interrupt me like that?","TWN":"大膽！竟敢搶走本王的台詞！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그런데 어떻게 알았느냐?","JPN":"ところでどうしてわかったのだ？","ENG":"But... how did you know?","TWN":"不過你怎麼知道？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음……. 그 규칙들이 만들어진 이유가 뭔지 짐작이 가거든요.","JPN":"えっと……そのルールが作られた理由が何なのか、見当がつきましたので。","ENG":"Mm... Because I think I know why those rules were made.","TWN":"嗯……我大概猜得到為什麼會有這些規矩。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무슨 소리를 하는지 모르겠구나.","JPN":"何を言ってるのかさっぱりわからぬな。","ENG":"I don't know what you're talking about.","TWN":"聽不懂你在說什麼！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"아무튼 아까 만든 요거트 스무디나 더 만들어 보아라. 이 몸의 잔이 벌써 비어 있지 않으냐!","JPN":"とにかく、さっき作ったヨーグルトスムージーをもっと作るのだ。\\n吾輩のグラスがもう空っぽではないか！","ENG":"Anyway, make some more of that yogurt smoothie you made earlier. My cup is empty already!","TWN":"總之你再多做一點剛剛的多多冰沙啦！沒看到本王的杯子空了嗎！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"윽…?!","JPN":"うっ……！！","ENG":"Ugh?","TWN":"唔…？！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"왜 그러세요?","JPN":"どうしました？","ENG":"What’s wrong?","TWN":"你怎麼了？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"화장실 마려.","JPN":"トイレ。","ENG":"I need to pee!","TWN":"我要去廁所！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"휴, 좋아요. 다른 악마 검증을 시도해볼 기회가 왔어요.","JPN":"ふぅ、いいでしょう。別の悪魔検証方法を試すチャンスが来ました。","ENG":"Whew, okay. I have one more chance to prove she's a devil.","TWN":"呼，太好了，趁現在試試其他查證方法！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"축성 받은 실을 이용해 결계를 만들어 두면, 분명 이 안에 들어오는 순간 괴로움에 몸부림치겠죠.","JPN":"聖別された糸を使って結界を作っておけば、\\nきっとこの中に入った瞬間、苦しみもがくでしょう。","ENG":"I'm going to create a ward with this blessed thread, and she'll writhe in pain at the moment she sets foot in it.","TWN":"利用祝福過的線設下結界，等到她進到結界後，就會立刻痛苦掙扎！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……이거라면 알러지 걱정도 없을 테고요.","JPN":"……これならアレルギーの心配もありませんし。","ENG":"... Without choking herself due to food allergies, of course.","TWN":"……而且還沒有過敏的疑慮。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸이 돌아왔노라!","JPN":"吾輩が戻ってきたぞ！","ENG":"I'm back!","TWN":"本王回來囉！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"하수인아, 얼른 스무디…","JPN":"下僕よ、早くスムージーを……","ENG":"My subject, my smoothie—","TWN":"手下，本王的冰沙…"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":" 앗?","JPN":"あっ？","ENG":" ah?","TWN":"哎呀？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Err?","TWN":"哎呀？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래서, 임금님 발에 뭔가 걸리는 바람에 넘어져서 다섯 바퀴를 뒹굴었다고?","JPN":"それで、王様の足に何か引っかかったせいで転んで、5回も回転したって？","ENG":"So, you tripped over something and rolled five times on the floor?","TWN":"你說你被不知道什麼東西絆倒，在地上滾了五圈？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"응……. 훌쩍…….","JPN":"うん……ぐすん……","ENG":"Yes... *Sniffle...*","TWN":"對啊……嗚嗚……"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L28_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그러다 진열장을 걷어차는 바람에 술병을 다 쏟아 버렸고?","JPN":"それでショーケースにぶつかって、お酒を倒して全部ぶちまけたって？","ENG":"And in the process, you kicked the display case and all the liquor bottles in it poured out?","TWN":"然後撞到酒櫃，所以酒都打翻了？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"히끅……. 그렇노라.","JPN":"ひっく……そうだ。","ENG":"*Hiccups...* That is right.","TWN":"嗚嗚……對啊。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그렇게 엎지른 술이 스며든 러그를 지나가던 손님이 밟았다가 미끄러진 거고?","JPN":"そしてぶちまけたお酒が染み込んだラグを、通りかかったお客さんが踏んで滑ったってこと？","ENG":"And a passing customer slipped on the alcohol-soaked rug?","TWN":"然後打翻的酒弄濕地毯，害客人踩到地毯時腳滑？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"... Yes.","TWN":"……對啊。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"날아간 손님 신발에 맞아서 코피가 났다는 거지?","JPN":"滑ったお客さんの靴が吹っ飛んで、アナタの顔に当たって鼻血が出たってことよね？","ENG":"And his shoe flew, hitting you in the nose, making you bleed?","TWN":"然後客人的鞋子飛出去，打到你害你流鼻血對吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으응…….","JPN":"うん……","ENG":"Y-yes...","TWN":"對啊……"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그레모리가 다시 떠올리게 해서 더 서글프도다.","JPN":"グレモリーが全部思い出させたせいで、また悲しくなってきたぞ。","ENG":"Gremory, why did you make me remember it? I'm sadder now.","TWN":"葛茉莉，聽你說完感覺像經歷二次傷害，"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"달콤한 게 먹고 싶구나.","JPN":"甘いものが食べたい。","ENG":"I want something sweet...","TWN":"我想要吃甜甜的東西。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"사탕이라도 줄까?","JPN":"キャンディーでもあげようか？","ENG":"Want some candy?","TWN":"給你糖果嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"괜찮다. 새로 온 하수인이 까망 열매가 들어간 맛있는 요거트 스무디를 만들어줄 것이니라.","JPN":"大丈夫だ。新人の下僕が黒い実が入った\\nおいしいヨーグルトスムージーを作ってくれるから。","ENG":"No, thank you. My new subject will make me her delicious yogurt smoothie with black fruit in it.","TWN":"不用了，新來的手下會做好喝的多多冰沙給我，裡面還會加黑色的果實喔～"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그렇지 않으냐?","JPN":"そうだろう？","ENG":"Isn't that right?","TWN":"對不對？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 네. 그럼 냉동실에서 블루베리를 좀 찾아볼까요?","JPN":"あっ、はい。では、冷凍庫からブルーベリーを持ってきますね。","ENG":"Oh, sure. Let me go to the freezer and grab some blueberries.","TWN":"喔，對！那我去冰箱找找有沒有藍莓～"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은 먼저 가서 기다리고 있겠노라.","JPN":"吾輩は先に行って待つとしよう。","ENG":"I'll go wait for my yogurt smoothie, then.","TWN":"那本王先去坐著等喝。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 우리 임금님이 니콜 양의 실력이 마음에 든 모양이야.","JPN":"フフッ、うちの王様はニコルちゃんの腕前が気に入ったようね。","ENG":"Hah hah. Little majesty must like what you made for her.","TWN":"呵呵，我們國王似乎很滿意妮可的手藝呢～"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저… 죄송해요. 제가 넘어지는 걸 잡아보려 했는데, 같이 미끄러지는 바람에…","JPN":"あの……すみません。転んでしまったのを助けようとしたら、\\n一緒に転んでしまって……","ENG":"Um... I'm sorry. I tried to stop her from falling, but I fell with her...","TWN":"那個…不好意思，我本來是想拉住她的，結果跟她一起滑倒…"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"너무 신경 쓰지 마. 워낙 자주 있는 일이라 임금님도 저렇게 금방 잊어버리거든.","JPN":"そんなに気にしないで。\\nいつものことだから、王様もああやってすぐ忘れるしね。","ENG":"No worries. Things like that happen all the time. She is used to them.","TWN":"沒關係，這種事是家常便飯，而且國王也不會放心上。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 자주 있는 일이요?","JPN":"え？　いつものことなんですか？","ENG":"Huh? They happen all the time?","TWN":"什麼？這是家常便飯嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"터가 안 좋다는 말, 들어 봤어?","JPN":"地相が悪いって言葉を聞いたことあるかしら？","ENG":"Have you heard of unlucky places?","TWN":"可能我們這裡風水不好吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"우리 가게는 다른 곳에 비해서 크고 작은 사고가 자주 일어나는 편이야.","JPN":"うちの店は他のところに比べて、色々な事故が起こりやすくてね。","ENG":"My shop seems to be one of them. It's more accident-prone than other bars.","TWN":"和其他地方比起來，我們店算是滿常發生一些大大小小的意外的。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"덕분에 가게에서 한 달을 넘게 버틴 직원이 없거든.","JPN":"おかげで一ヶ月以上耐えたスタッフがいないのよ。","ENG":"That's why no employee I hired has lasted longer than a month.","TWN":"也因為這樣，根本沒有員工可以在這裡待超過一個月以上。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(그야 당연히 이곳에 악마가 있기 때문…….)","JPN":"(それはここに悪魔がいるせい……)","ENG":"(Well, that's because your place is haunted by a devil...)","TWN":"(這不是廢話嗎？這裡有魔鬼欸……)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(……이라고 말하고 싶지만, 잘못 말했다간 죄 없는 그레모리 씨에게 괜한 불똥이 튈지도 몰라요.)","JPN":"(……と言いたいところですが、下手したら罪のないグレモリーさんに\\n余計な火の粉が降りかかるかもしれません。)","ENG":"(... is what I want to say, but I'd better not. I don't want to put innocent Gremory in danger.)","TWN":"(……真想這麼跟她說，但又怕牽累到無辜的她。)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"베리~ 베리~ 스무디~","JPN":"ベリ～ベリ～スム～ジ～♪","ENG":"Berry, berry, smoothie!","TWN":"莓果～莓果～冰沙～"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 네에! 지금 가요!","JPN":"はい、はい！　今行きます！","ENG":"Yes! I'm coming!","TWN":"是！！立刻送過去！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"呵……"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};